INSERT INTO public."BIBLIOTECA-LIDERANÇA" ("id","area","livro","autor","link","imagem","sobre","beneficios","download","Capa-area","aula","resumo_capitulos","questoes_resumo","resumo_gerado_em") VALUES
(157,'Liderança','Os 7 Hábitos das Pessoas Altamente Eficazes','Stephen R. Covey','https://online.fliphtml5.com/zmzll/ohpe/','https://izspjvegxdfgkgibpyst.supabase.co/storage/v1/object/public/imagens/noticias/811jUvTg4FLSL1500jpg-1766362409928.webp','Em "Os 7 Hábitos das Pessoas Altamente Eficazes", Stephen Covey apresenta um guia para o desenvolvimento pessoal e profissional baseado em princípios de caráter e ética. O livro explora a mudança de paradigmas para alcançar a eficácia, desde a dependência à independência e, finalmente, à interdependência, através de hábitos como proatividade, começar com o objetivo em mente e buscar primeiro compreender, depois ser compreendido. Para estudantes de Direito, os princípios do livro oferecem ferrame','A ênfase na ética e na construção de relacionamentos sólidos contribui para uma carreira de sucesso e impacto positivo. ','https://drive.google.com/file/d/17GD_cieV8OglF7ST4hcC6i9CnqGxtCxP/view?usp=drivesdk','https://phzcazcyjhlmdchcjagy.supabase.co/storage/v1/object/public/CAPA%20MODULO/lide.gif',NULL,NULL,NULL,NULL),
(158,'Liderança','Liderança: A Inteligência Emocional na Formação do Líder de Sucesso','Daniel Goleman','https://online.fliphtml5.com/zmzll/hxux/','https://izspjvegxdfgkgibpyst.supabase.co/storage/v1/object/public/imagens/noticias/719reSKFCkLSL1500jpg-1766362414414.webp','Descubra como a inteligência emocional impulsiona a liderança eficaz. Daniel Goleman explora as habilidades cruciais como autoconsciência, autogestão, empatia e habilidades sociais, mostrando como aplicá-las para inspirar e motivar equipes, construir relacionamentos sólidos e alcançar o sucesso. Para estudantes de Direito, o livro oferece insights valiosos sobre comunicação persuasiva, negociação eficaz e gestão de conflitos.','Aprimore suas habilidades interpessoais e torne-se um líder influente e respeitado no campo jurídico. ','https://drive.google.com/file/d/1TlxopBOZm1cYKL80Fe6pnAtxT6ze8P2i/view?usp=drivesdk','https://phzcazcyjhlmdchcjagy.supabase.co/storage/v1/object/public/CAPA%20MODULO/lide.gif',NULL,NULL,NULL,NULL),
(159,'Liderança','O Monge e o Executivo: Uma História sobre a Essência da Liderança','James C. Hunter','https://online.fliphtml5.com/zmzll/mdlk/','https://izspjvegxdfgkgibpyst.supabase.co/storage/v1/object/public/imagens/noticias/81azm3rAm3LSL1500jpg-1766360465068.webp','Um executivo bem-sucedido, mas frustrado, busca respostas para seus problemas de liderança em um mosteiro. Lá, ele aprende com um monge a verdadeira essência da liderança servidora, baseada em amor, paciência, bondade, humildade, respeito, altruísmo, perdão e honestidade. Uma jornada inspiradora sobre como influenciar e motivar pessoas, transformando o ambiente de trabalho e a vida pessoal.','Para estudantes de Direito, a obra oferece valiosas lições sobre ética, persuasão e gestão de conflitos. A compreensão da liderança servidora aprimora a capacidade de construir relações profissionais sólidas, negociar com eficácia e promover a justiç','https://drive.google.com/file/d/1449BKORDekwr-ASb_DACzj4guxhmVpoE/view?usp=drivesdk','https://phzcazcyjhlmdchcjagy.supabase.co/storage/v1/object/public/CAPA%20MODULO/lide.gif',NULL,NULL,NULL,NULL),
(160,'Liderança','Comece pelo Porquê','Simon Sinek','https://online.fliphtml5.com/zmzll/chfp/','https://izspjvegxdfgkgibpyst.supabase.co/storage/v1/object/public/imagens/noticias/71M6czhxmTLSL1500jpg-1766362419236.webp','Comece pelo Porquê explora como líderes inspiradores pensam, agem e comunicam. Simon Sinek revela que as pessoas não compram o que você faz, mas por que você faz. Empresas e líderes que começam com o "porquê" (propósito) inspiram mais, fidelizam clientes e criam culturas de sucesso.','Para estudantes de Direito, o livro oferece insights sobre persuasão, argumentação e construção de narrativas convincentes, habilidades cruciais para a advocacia. Ajuda a definir um propósito claro na carreira jurídica e a inspirar confiança em clien','https://drive.google.com/file/d/1xA55Xi6juTHzaogcjqS4JFuQnG7ApwgW/view?usp=drivesdk','https://phzcazcyjhlmdchcjagy.supabase.co/storage/v1/object/public/CAPA%20MODULO/lide.gif',NULL,NULL,NULL,NULL),
(161,'Liderança','O Poder da Autorresponsabilidade','Paulo Vieira','https://online.fliphtml5.com/zmzll/xnmv/','https://izspjvegxdfgkgibpyst.supabase.co/storage/v1/object/public/imagens/noticias/71hoMGLdCLSL1500jpg-1766362423623.webp','Assuma o controle da sua vida! "O Poder da Autorresponsabilidade" de Paulo Vieira te convida a abandonar a vitimização e abraçar a responsabilidade por seus resultados. Descubra as ferramentas para transformar sua realidade, alcançar seus objetivos e construir a vida que você deseja, através de atitudes proativas e conscientes. Para estudantes de Direito, a autorresponsabilidade é crucial.','Melhora a organização, a disciplina nos estudos e a capacidade de argumentação. Aumenta o foco para enfrentar a pressão da carreira jurídica e impulsiona a busca por soluções inovadoras e eficazes. ','https://drive.google.com/file/d/1omyMkVm0ztIUApg-dovGVhLUPVcZWnJS/view?usp=drivesdk','https://phzcazcyjhlmdchcjagy.supabase.co/storage/v1/object/public/CAPA%20MODULO/lide.gif',NULL,NULL,NULL,NULL),
(162,'Liderança','A Coragem para Liderar','Brené Brown','https://online.fliphtml5.com/zmzll/felb/','https://izspjvegxdfgkgibpyst.supabase.co/storage/v1/object/public/imagens/noticias/91CDfj7nf8LSL1500jpg-1766362430091.webp','Em A Coragem para Liderar, Brené Brown explora como a vulnerabilidade e a empatia são pilares da verdadeira liderança. A autora mostra que coragem não é ausência de medo, mas a disposição de enfrentar incertezas, assumir riscos e construir relações autênticas. A obra inspira líderes a criarem ambientes de confiança, diálogo e inovação, capazes de transformar equipes e fortalecer valores humanos.',NULL,'https://drive.google.com/file/d/1-GPXdlam39Atjo9vziaiORUcIAGykJ48/view?usp=drivesdk','https://phzcazcyjhlmdchcjagy.supabase.co/storage/v1/object/public/CAPA%20MODULO/lide.gif',NULL,NULL,NULL,NULL),
(163,'Liderança','Responsabilidade Extrema','Jocko Willink & Leif Babin','https://online.fliphtml5.com/zmzll/ilfq/','https://izspjvegxdfgkgibpyst.supabase.co/storage/v1/object/public/imagens/noticias/51lkt3xn7SLSL1000jpg-1766362433007.webp','Em "Responsabilidade Extrema", Jocko Willink e Leif Babin, ex-Navy SEALs, compartilham princípios de liderança aprendidos em combate, aplicáveis em qualquer contexto. A obra enfatiza a importância da responsabilidade total, da comunicação clara e da execução estratégica para alcançar o sucesso em equipe. Para estudantes de Direito, o livro oferece insights valiosos sobre liderança, tomada de decisões sob pressão e a importância da responsabilidade na prática jurídica, essenciais para construir u','Estudantes de Direito aprendem a liderar com ética, comunicação clara e resiliência, qualidades essenciais para atuar em equipes jurídicas e conduzir negociações complexas com firmeza e empatia.','https://drive.google.com/file/d/1omyMkVm0ztIUApg-dovGVhLUPVcZWnJS/view?usp=drivesdk','https://phzcazcyjhlmdchcjagy.supabase.co/storage/v1/object/public/CAPA%20MODULO/lide.gif',NULL,NULL,NULL,NULL),
(164,'Liderança','Os 5 Desafios das Equipes','Patrick Lencioni','https://online.fliphtml5.com/zmzll/qojt/','https://izspjvegxdfgkgibpyst.supabase.co/storage/v1/object/public/imagens/noticias/61Hg3ubq2hLSL1049jpg-1766362437129.webp','Em "Os 5 Desafios das Equipes", Patrick Lencioni explora as dinâmicas disfuncionais que sabotam o sucesso de um grupo. Ausência de confiança, medo de conflitos, falta de comprometimento, evitar responsabilização e desatenção aos resultados são os obstáculos a serem superados para alcançar alta performance e coesão. Uma fábula envolvente com lições valiosas para qualquer equipe.','Para estudantes de Direito, o livro oferece insights sobre negociação, resolução de conflitos e dinâmicas de grupo, habilidades cruciais na atuação jurídica. A compreensão das fraquezas de uma equipe prepara o profissional para liderar, colaborar e c','https://drive.google.com/file/d/1OHUkcUjqYd_BeFeqeQpwvF853Vi2P4Dl/view?usp=drivesdk','https://phzcazcyjhlmdchcjagy.supabase.co/storage/v1/object/public/CAPA%20MODULO/lide.gif',NULL,NULL,NULL,NULL),
(165,'Liderança','Radical Candor','Kim Scott','https://online.fliphtml5.com/zmzll/whkp/','https://izspjvegxdfgkgibpyst.supabase.co/storage/v1/object/public/imagens/noticias/81Yd6Q6geBLSL1500jpg-1766362442213.webp','Radical Candor, de Kim Scott, ensina a equilibrar franqueza e empatia na comunicação profissional. O livro detalha como ser honesto e direto sem ser cruel, criando relações de confiança e promovendo um ambiente de trabalho mais colaborativo e produtivo. A obra oferece um guia prático para líderes que desejam desenvolver equipes de alto desempenho através de feedback construtivo e genuíno.','Para estudantes de Direito, a obra capacita a comunicação eficaz, essencial na advocacia. Ajuda a construir relacionamentos profissionais sólidos, aprimorar a capacidade de argumentação e a lidar com conflitos de forma construtiva. ','https://drive.google.com/file/d/1pJF-OAGutxgpQzc69gQOmT-QyAu7Bciz/view?usp=drivesdk','https://phzcazcyjhlmdchcjagy.supabase.co/storage/v1/object/public/CAPA%20MODULO/lide.gif',NULL,NULL,NULL,NULL),
(166,'Liderança','As 21 Irrefutáveis Leis da Liderança','John C. Maxwell','https://online.fliphtml5.com/zmzll/fhjh/','https://izspjvegxdfgkgibpyst.supabase.co/storage/v1/object/public/imagens/noticias/91VdtpdFrLSL1500jpg-1766362447716.webp','Descubra os princípios essenciais para se tornar um líder de sucesso em "As 21 Irrefutáveis Leis da Liderança". John C. Maxwell revela, de forma clara e prática, as leis que regem a liderança eficaz, desde a Lei do Limite até a Lei do Legado.','Aprenda a influenciar, motivar e inspirar equipes, alcançando resultados extraordinários em qualquer área da sua vida. Para estudantes de Direito, o livro oferece insights valiosos sobre persuasão, negociação e gestão de conflitos, habilidades crucia','https://drive.google.com/file/d/1pJF-OAGutxgpQzc69gQOmT-QyAu7Bciz/view?usp=drivesdk','https://phzcazcyjhlmdchcjagy.supabase.co/storage/v1/object/public/CAPA%20MODULO/lide.gif',NULL,NULL,NULL,NULL);